import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useParams, useNavigate } from 'react-router-dom';

const Forum = () => {
  const { currentUser } = useAuth();
  const { postId } = useParams();
  const navigate = useNavigate();
  const [posts, setPosts] = useState([]);
  const [currentPost, setCurrentPost] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showNewPostForm, setShowNewPostForm] = useState(false);
  const [newPost, setNewPost] = useState({
    title: '',
    content: '',
    category: 'General',
    anonymous: false
  });
  const [replyContent, setReplyContent] = useState('');
  const [replyAnonymous, setReplyAnonymous] = useState(false);
  const [error, setError] = useState('');

  // Load forum posts or single post
  useEffect(() => {
    if (postId) {
      fetchPost(postId);
    } else {
      fetchPosts();
    }
  }, [postId]);

  const fetchPosts = async () => {
    try {
      setLoading(true);
      const response = await fetch('/api/forum/posts');
      if (!response.ok) throw new Error('Failed to fetch posts');

      const data = await response.json();
      if (data.success) {
        setPosts(data.data);
      } else {
        setError('Failed to load posts');
      }
    } catch (error) {
      console.error('Error fetching posts:', error);
      setError('Cannot connect to server. Please check if backend is running.');
    } finally {
      setLoading(false);
    }
  };

  const fetchPost = async (id) => {
    try {
      setLoading(true);
      const response = await fetch(`/api/forum/posts/${id}`);
      if (!response.ok) throw new Error('Failed to fetch post');

      const data = await response.json();
      if (data.success) {
        setCurrentPost(data.data);
        // Track view
        await trackView(id);
      } else {
        setError('Failed to load post');
      }
    } catch (error) {
      console.error('Error fetching post:', error);
      setError('Cannot load post. Make sure backend server is running.');
    } finally {
      setLoading(false);
    }
  };

  const trackView = async (id) => {
    try {
      await fetch(`/api/forum/posts/${id}/view`, {
        method: 'POST'
      });
    } catch (error) {
      console.error('Error tracking view:', error);
    }
  };

  const handleCreatePost = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Please log in to create a post');
        return;
      }

      const response = await fetch('/api/forum/posts', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(newPost)
      });

      const data = await response.json();

      if (data.success) {
        setPosts([data.data, ...posts]);
        setNewPost({ title: '', content: '', category: 'General', anonymous: false });
        setShowNewPostForm(false);
        setError('');
      } else {
        setError(data.message || 'Failed to create post');
      }
    } catch (error) {
      console.error('Error creating post:', error);
      setError('Network error. Please try again.');
    }
  };

  const handleAddReply = async (e) => {
    e.preventDefault();
    if (!replyContent.trim()) return;

    try {
      if (!currentUser) {
        setError('Please log in to reply to posts');
        return;
      }

      const token = localStorage.getItem('token');
      if (!token) {
        setError('Authentication required. Please log in again.');
        return;
      }

      const response = await fetch(`/api/forum/posts/${postId}/reply`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({
          content: replyContent,
          anonymous: replyAnonymous
        })
      });

      const data = await response.json();

      if (data.success) {
        setCurrentPost(data.data);
        setReplyContent('');
        setReplyAnonymous(false);
        setError('');
      } else {
        setError(data.message || 'Failed to post reply');
      }
    } catch (error) {
      console.error('Error adding reply:', error);
      setError('Network error. Please check if backend server is running.');
    }
  };

  // ... rest of your component (UI rendering)
  // Keep your existing UI code as it was

};

export default Forum;
